importScripts("../template.js");async function onWasmMessage(e,...t){if("convertERROR"!=e)if("convertOK"!=e)if("exportModelFileReady"!=e);else{let e,a,s=UTF8ToString(t[0]);try{e=FS.readFile(s.substring(0,s.lastIndexOf("."))+".bin");FS.unlink(s.substring(0,s.lastIndexOf("."))+".bin")}catch(t){try{e=FS.readFile(s.substring(0,s.lastIndexOf("."))+"_0.bin");FS.unlink(s.substring(0,s.lastIndexOf("."))+"_0.bin")}catch(t){e=void 0}}try{a=FS.readFile(s.substring(0,s.lastIndexOf("."))+".mtl");FS.unlink(s.substring(0,s.lastIndexOf("."))+".mtl")}catch(e){a=void 0}try{postMessage({type:"exportModelFileReady",data:{fileData:FS.readFile(s),binData:e,mtlData:a}});FS.unlink(s)}catch(e){}}else{let e=UTF8ToString(t[0]);postMessage({type:"convertOK",data:{name:e.split("/").pop(),data:FS.readFile(e)}});FS.unlink(e)}else postMessage({type:"convertError"})}Module={};Module.onRuntimeInitialized=function(){FS.mkdir("/models");FS.mount(MEMFS,{},"/models")};addEventListener("message",(({data:{type:e,data:t}})=>{if("createFile"==e.split("_")[0]){FS.writeFile("/models/"+t.path,t.data);FS.syncfs(!0,(()=>{postMessage({type:"createFile_"+e.split("_")[1],once:!0})}))}else if("createDir"==e.split("_")[0]){FS.mkdir("/models/"+t);FS.mount(MEMFS,{},"/models/"+t);postMessage({type:"createDir_"+e.split("_")[1],once:!0})}else if("getVirtualFile"==e.split("_")[0])postMessage({type:"getVirtualFile_"+e.split("_")[1],once:!0,data:FS.readFile(t,{encoding:"binary"})});else if("export"==e)_exportModel(allocateUTF8("/models/"+t.path),allocateUTF8(t.path.substring(0,t.path.lastIndexOf("."))),allocateUTF8(t.format));else if("parseModel"==e){modelPath="/models/"+t;textureData={};_parseModel(allocateUTF8("/models/"+t),allocateUTF8(t.substring(0,t.lastIndexOf(".")).split("/").pop()))}}));